void ft_print_alphabet(void) {
    char c = 'a';
    while (c <= 'z') {
        write(1, &c, 1);
        c++;
    }
    write(1, "\n", 1);
}

void ft_print_reverse_alphabet(void) {
    char c = 'z';
    while (c >= 'a') {
        write(1, &c, 1);
        c--;
    }
    write(1, "\n", 1);
}

void ft_print_numbers(void) {
    char c = '0';
    while (c <= '9') {
        write(1, &c, 1);
        c++;
    }
    write(1, "\n", 1);
}

void ft_is_negative(int n) {
    if (n < 0)
        write(1, "N", 1);
    else
        write(1, "P", 1);
    write(1, "\n", 1);
}

void ft_print_comb(void) {
    char a, b, c;
    for (a = '0'; a <= '7'; a++) {
        for (b = a + 1; b <= '8'; b++) {
            for (c = b + 1; c <= '9'; c++) {
                write(1, &a, 1);
                write(1, &b, 1);
                write(1, &c, 1);
                if (a != '7')
                    write(1, ", ", 2);
            }
        }
    }
    write(1, "\n", 1);
}

void ft_putnbr(int nb) {
    if (nb == -2147483648) {
        write(1, "-2147483648", 11);
        return;
    }
    if (nb < 0) {
        write(1, "-", 1);
        nb = -nb;
    }
    if (nb >= 10)
        ft_putnbr(nb / 10);
    char c = nb % 10 + '0';
    write(1, &c, 1);
}

exercises.tests:
int main() {
    ft_putnbr(42);
    write(1, "\n", 1);
    ft_putnbr(-123);
    write(1, "\n", 1);
    ft_putnbr(0);
    write(1, "\n", 1);
    return 0;
}

