void ft_print_combn(int n) {
    if (n < 1 || n > 9) return;
    int digits[10], i;
    void print(int pos, int last) {
        if (pos == n) {
            for (i = 0; i < n; i++) {
                char c = digits[i] + '0';
                write(1, &c, 1);
            }
            if (digits[0] != 10 - n) write(1, ", ", 2);
            return;
        }
        for (int d = last + 1; d <= 9; d++) {
            digits[pos] = d;
            print(pos + 1, d);
        }
    }
    print(0, -1);
    write(1, "\n", 1);
}

char *ft_strcpy(char *dest, char *src) {
    int i = 0;
    while (src[i]) {
        dest[i] = src[i];
        i++;
    }
    dest[i] = '\0';
    return dest;
}

exercises.tests:
int main() {
    char dest[100];
    ft_strcpy(dest, "Hello");
    printf("%s\n", dest);
    return 0;
}

